import React, { memo } from "react";

function CardResumen({
  titulo,
  valor,
  subtitulo,
  icono,
  colorClase  = "text-[#691C32]",
  bgClase     = "bg-[rgba(105,28,50,0.06)]",
  borderColor = "#D4C4B0",
}) {
  return (
    <div
      className="bg-white rounded-xl p-6 transition-all duration-300 ease-in-out hover:-translate-y-0.5 animate-fade-in"
      style={{
        borderTop:  `4px solid ${borderColor}`,
        boxShadow:  "0 4px 12px rgba(0,0,0,0.08)",
      }}
      onMouseEnter={e => { e.currentTarget.style.boxShadow = "0 8px 20px rgba(0,0,0,0.12)"; }}
      onMouseLeave={e => { e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,0.08)"; }}
    >
      <div className="flex items-start justify-between">
        <div className="flex-1 min-w-0">
          <p
            className="text-xs font-semibold uppercase tracking-wide mb-2"
            style={{ color: "#666666", letterSpacing: "0.5px" }}
          >
            {titulo}
          </p>
          <p className={`text-5xl font-bold leading-none ${colorClase}`}>
            {valor}
          </p>
          {subtitulo && (
            <p className="text-sm mt-2" style={{ color: "#666666" }}>
              {subtitulo}
            </p>
          )}
        </div>
        <div
          className={`w-12 h-12 rounded-xl ${bgClase} flex items-center justify-center text-2xl shrink-0 ml-3`}
        >
          {icono}
        </div>
      </div>
    </div>
  );
}

export default memo(CardResumen);
